using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e2+5;
int n,m,a[MAXN][MAXN],b[MAXN][MAXN],mi,mx,dis[MAXN],vis[MAXN];
void dij()
{
    cli(dis);
    cl(vis);
    dis[1]=0;
    FOR(t,1,n)
    {
        int mn=llinf,u=0;
        FOR(i,1,n)
        {
            if(!vis[i]&&dis[i]<mn)
            {
                mn=dis[i],u=i;
            }
        }
        if(!u)break;
        vis[u]=1;
        FOR(v,1,n)
        {
            if(dis[v]>dis[u]+a[u][v])
            {
                dis[v]=dis[u]+a[u][v];
            }
        }
    }
}
signed main(void)
{
    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cout.tie(0);
    cin>>n>>m;
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
            a[i][j]=llinf;
        }
    }
    FOR(i,1,m)
    {
        int x,y,z;
        cin>>x>>y>>z;
        a[x][y]=a[y][x]=z;
    }
    dij();
    mi=dis[n];
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
            if(a[i][j]==inf)continue;
            int tmp=a[i][j];
            a[i][j]=a[j][i]=tmp*2;
            dij();
            mx=max(mx,dis[n]);
            a[i][j]=a[j][i]=tmp;
        }
    }
    cout<<mx-mi;
    return false;
}
